import network
import uasyncio as asyncio
import usocket
import json

# Initialize Wi-Fi connection
def connect_wifi(ssid, password):
    sta_if = network.WLAN(network.STA_IF)
    if not sta_if.isconnected():
        print('Connecting to network...')
        sta_if.active(True)
        sta_if.connect(ssid, password)
        while not sta_if.isconnected():
            pass
    print('Network config:', sta_if.ifconfig())

# WebSocket server handler
async def handle_websocket(reader, writer):
    addr = writer.get_extra_info('peername')
    print(f"Connection from {addr}")

    async for data in reader:
        message = data.decode()
        try:
            command = json.loads(message)
            if command['action'] == 'turn_on':
                print("Turning on device")
                # Add your code here to control the IoT device
            else:
                print(f"Unknown action: {command['action']}")
        except json.JSONDecodeError:
            print("Invalid JSON received")

    writer.close()
    await writer.wait_closed()

# Start WebSocket server
async def start_websocket_server():
    server = await asyncio.start_server(handle_websocket, '0.0.0.0', 8765)
    addr = server.sockets[0].getsockname()
    print(f'Serving on {addr}')

    async with server:
        await server.serve_forever()

# Main function
